import { Component } from '@angular/core';
import { ApiService } from '../../services/api.service';
import { Router } from '@angular/router';

@Component({
  selector: 'app-search',
  templateUrl: './search.component.html'
})
export class SearchComponent {
  public source = '';
  public destination = '';
  public date = new Date().toISOString().slice(0, 10);
  public buses: any[] = [];
  public errorMessage = '';
  public searched = false;
  public today = new Date().toISOString().slice(0, 10);

  constructor(private api: ApiService, private router: Router) {}

  public search() {
    this.errorMessage = '';
    this.searched = false;
    if (!this.source || !this.destination || !this.date) {
      this.errorMessage = 'Please fill in all search fields.';
      return;
    }
    this.api.searchBuses(this.source, this.destination, this.date).subscribe({
      next: (result: any) => {
        this.buses = result;
        this.searched = true;
      },
      error: err => {
        this.errorMessage = err.error?.title || err.error || err.statusText || 'Search failed.';
        this.searched = true;
      }
    });
  }

  public book(busId: string) {
    this.router.navigate(['/booking', busId]);
  }
}
<div class="search-hero">
  <h1>Find Buses</h1>
  <div class="search-form card">
    <div class="search-fields">
      <div class="form-group">
        <label>From</label>
        <input [(ngModel)]="source" name="source" placeholder="e.g. Chennai" required />
      </div>
      <div class="form-group">
        <label>To</label>
        <input [(ngModel)]="destination" name="destination" placeholder="e.g. Bangalore" required />
      </div>
      <div class="form-group">
        <label>Travel Date</label>
        <input type="date" [(ngModel)]="date" name="date" [min]="today" required />
      </div>
      <button class="btn btn-primary" (click)="search()">Search Buses</button>
    </div>
    <p *ngIf="errorMessage" class="alert alert-error">{{ errorMessage }}</p>
  </div>
</div>

<div *ngIf="buses.length === 0 && searched" class="card" style="text-align:center;padding:40px">
  <p style="font-size:18px;color:#666">No buses found for this route on the selected date.</p>
  <p>Try a different date or route.</p>
</div>

<div *ngIf="buses.length > 0" class="search-results">
  <h3 class="results-header">{{ buses.length }} Bus{{ buses.length > 1 ? 'es' : '' }} Found</h3>
  <div *ngFor="let bus of buses" class="bus-card">
    <div class="bus-card-main">
      <div class="bus-info">
        <div class="bus-name">{{ bus.busName || bus.registrationNumber }}</div>
        <div *ngIf="bus.busType" class="bus-type">{{ bus.busType }}</div>
        <div class="bus-reg">{{ bus.registrationNumber }}</div>
        <div class="operator-name" *ngIf="bus.operatorName">Operated by: {{ bus.operatorName }}</div>
      </div>

      <div class="bus-timing">
        <div class="time-block">
          <span class="time">{{ bus.departureTime }}</span>
          <span class="city">{{ bus.route.source }}</span>
          <span class="stop-label">📍 {{ bus.boardingPoint || bus.route.source }}</span>
        </div>
        <div class="duration-arrow">
          <div class="arrow-line"></div>
          <span class="bus-icon">🚌</span>
        </div>
        <div class="time-block">
          <span class="time">{{ bus.arrivalTime || '—' }}</span>
          <span class="city">{{ bus.route.destination }}</span>
          <span class="stop-label">📍 {{ bus.droppingPoint || bus.route.destination }}</span>
        </div>
      </div>

      <div class="bus-price-section">
        <div class="price">₹{{ bus.price }}</div>
        <div class="seats-left" [class.low-seats]="bus.availableSeats <= 5">
          {{ bus.availableSeats }} seat{{ bus.availableSeats !== 1 ? 's' : '' }} available
        </div>
        <button
          class="btn btn-primary btn-book"
          [disabled]="bus.availableSeats === 0"
          (click)="book(bus.id)">
          {{ bus.availableSeats > 0 ? 'Select Seats' : 'Sold Out' }}
        </button>
      </div>
    </div>
  </div>
</div>
